module top_module(
  input clk,
  input ld,
  input d,
  output reg q
);reg [7:0] unused_shift_reg;

always @(posedge clk) begin
  if(ld) begin
    unused_shift_reg <= d;
  end else begin
    unused_shift_reg <= {unused_shift_reg[6:0], d};
  end
end

assign q = unused_shift_reg[0];

endmodule
